mapper.sql:
from user u
         inner join user_role_relation urr on u.id = urr.user_id and urr.source_id = #{request.organizationId}
         left join department d on u.department_id = d.id and d.organization_id = #{request.organizationId}
where u.deleted = 0

    and u.department_id = #{request.departmentId}


    and (
        u.name like concat('%', #{request.keyword}, '%')
            or u.email like concat('%', #{request.keyword}, '%')
            or u.phone like concat('%', #{request.keyword}, '%')
        )


    and u.enable = #{request.enable}


    and u.sync_status = #{request.syncStatus}
